exercises.solution_code:
#include <iostream>

int calculateFormula(int a, int b, int c, int d)
{
    int step1 = a * b;
    int step2 = c / d;
    int result = step1 + step2;  // Fixed: changed - to +
    return result;
}

int main()
{
    int a{}, b{}, c{}, d{};
    std::cin >> a >> b >> c >> d;

    int answer = calculateFormula(a, b, c, d);

    std::cout << answer << '\n';

    return 0;
}

