exercises.solution_code:
#include <iostream>
#include <cassert>

int calculateAverage(int a, int b)
{
    assert(a > 0);  // Precondition: a must be positive
    assert(b > 0);  // Precondition: b must be positive

    int average = (a + b) / 2;
    return average;
}

int main()
{
    int a{}, b{};
    std::cin >> a >> b;

    int result = calculateAverage(a, b);

    std::cout << result << '\n';

    return 0;
}
